/**
 * PrajnaAGI CMS Loader
 * Dynamically fetches and renders content from JSON files (generated by build scripts or manual updates)
 */

async function fetchJSON(url) {
    try {
        const response = await fetch(url);
        if (!response.ok) throw new Error(`HTTP error! status: ${response.status}`);
        return await response.json();
    } catch (e) {
        console.error(`Could not fetch ${url}:`, e);
        return null;
    }
}

// ── CATEGORY PAGE LOADER ──────────────────────────────────────────
async function loadCMSCategoryArticles(containerId, categoryName) {
    const container = document.getElementById(containerId);
    if (!container) return;

    const data = await fetchJSON('content/articles.json');
    if (!data || !data.articles) return;

    const filtered = data.articles.filter(a => a.category === categoryName);
    
    if (filtered.length === 0) {
        container.innerHTML = '<p style="grid-column:1/-1; text-align:center; padding:2rem; opacity:0.6;">इस श्रेणी में अभी कोई लेख नहीं हैं।</p>';
        return;
    }

    container.innerHTML = filtered.map(article => `
        <a href="article.html?title=${encodeURIComponent(article.title)}" class="clickable-card">
            <div style="height:200px; background:url('${article.image || 'https://images.unsplash.com/photo-1451187580459-43490279c0fa?auto=format&fit=crop&q=80&w=600'}') center/cover;"></div>
            <div style="padding:1.5rem;">
                <span class="tag" style="color:var(--accent); font-weight:800; font-size:0.75rem;">${article.tag || categoryName}</span>
                <h3 style="margin:10px 0 8px; font-size:1.2rem;">${article.title}</h3>
                <p style="color:var(--text-muted); font-size:0.9rem; line-height:1.5;">${article.summary}</p>
                <div class="progress-bar">
                    <div class="progress-fill" data-percent="100%"></div>
                </div>
            </div>
        </a>
    `).join('');

    // Re-observe new elements
    if (window.revealObserver) {
        container.querySelectorAll('.clickable-card').forEach(el => window.revealObserver.observe(el));
    }
}

// ── HOMEPAGE LOADERS ──────────────────────────────────────────────
async function loadCMSLatestNews(containerId) {
    const container = document.getElementById(containerId);
    if (!container) return;

    const data = await fetchJSON('content/articles.json');
    if (!data || !data.articles) return;

    // Last 6 articles
    const latest = data.articles.slice(0, 6);

    container.innerHTML = latest.map(article => `
        <a href="article.html?title=${encodeURIComponent(article.title)}" class="clickable-card">
            <div style="height:180px; background:url('${article.image || 'https://images.unsplash.com/photo-1451187580459-43490279c0fa?auto=format&fit=crop&q=80&w=600'}') center/cover;"></div>
            <div style="padding:1.4rem;">
                <span class="tag" style="color:var(--accent); font-weight:800; font-size:0.7rem;">${article.category}</span>
                <h3 style="margin:8px 0; font-size:1.1rem;">${article.title}</h3>
                <p style="color:var(--text-muted); font-size:0.85rem; line-height:1.4;">${article.summary}</p>
            </div>
        </a>
    `).join('');

    if (window.revealObserver) {
        container.querySelectorAll('.clickable-card').forEach(el => window.revealObserver.observe(el));
    }
}

// ── TICKER LOADER ────────────────────────────────────────────────
async function loadCMSTicker(containerClass) {
    const tracks = document.querySelectorAll(`.${containerClass}`);
    if (tracks.length === 0) return;

    const tickerData = await fetchJSON('content/ticker.json');
    if (!tickerData) return;

    const tickerHTML = tickerData.map(item => `
        <span>${item.text}</span><span>•</span>
    `).join('');

    tracks.forEach(track => {
        track.innerHTML = tickerHTML + tickerHTML; // Double for seamless loop
    });
}

// ── INITIALIZE ON DOM LOAD ───────────────────────────────────────
document.addEventListener('DOMContentLoaded', () => {
    // Detect page and load appropriate CMS content
    const bodyId = document.body.id;
    
    // Auto-detect based on grid IDs if body ID isn't set
    if (document.getElementById('cms-latest-grid')) {
        loadCMSLatestNews('cms-latest-grid');
    }
    
    if (document.querySelector('.ticker-track')) {
        loadCMSTicker('ticker-track');
    }

    // Category detection
    const categoryGrids = [
        { id: 'cms-tech-grid', cat: 'तकनीक' },
        { id: 'cms-science-grid', cat: 'विज्ञान' },
        { id: 'cms-space-grid', cat: 'अंतरिक्ष' },
        { id: 'cms-environment-grid', cat: 'पर्यावरण' },
        { id: 'cms-health-grid', cat: 'स्वास्थ्य' }
    ];

    categoryGrids.forEach(grid => {
        if (document.getElementById(grid.id)) {
            loadCMSCategoryArticles(grid.id, grid.cat);
        }
    });
});

